/**
 * Tray bridge — push frontend state into the system tray.
 *
 * The Rust shell owns the tray icon + menu; this module is the thin
 * adapter that translates store changes into `invoke()` calls so the
 * tray stays in sync with what the user sees in the dashboard.
 *
 * All exports are safe in web mode (they resolve to no-ops).
 */

import { isTauri } from './index.js';
import { useConnectionStore, type WsStatus, type ApiStatus } from '../services/connectionStore.js';
import { isMockMode } from '../services/eventStream.js';
import { subscribeAgents } from '../services/agentRegistry.js';
import type { AgentInfo } from '../types/agent.js';

export type TrayConnectionTag = 'connected' | 'reconnecting' | 'down' | 'mock';

/**
 * Map the dashboard's WsStatus + ApiStatus into the four-state tag the
 * tray icon understands. The tray is intentionally coarse — users
 * don't need to see every backoff transition.
 */
export function deriveTrayState(
  ws: WsStatus,
  api: ApiStatus,
  mock: boolean,
): TrayConnectionTag {
  if (mock || ws === 'fallback-mock') return 'mock';
  if (ws === 'open' && api !== 'down') return 'connected';
  if (ws === 'connecting' || ws === 'reconnecting') return 'reconnecting';
  return 'down';
}

async function safeInvoke<T = unknown>(cmd: string, args?: Record<string, unknown>): Promise<T | null> {
  if (!isTauri()) return null;
  try {
    const { invoke } = await import('@tauri-apps/api/core');
    return (await invoke(cmd, args)) as T;
  } catch (err) {
    console.warn(`[tauri-bridge] invoke ${cmd} failed`, err);
    return null;
  }
}

/** Push the current connection state to the tray. Safe in web mode. */
export async function updateTrayConnectionState(state: TrayConnectionTag): Promise<void> {
  await safeInvoke('update_tray_connection', { status: state });
}

/** Push the agent roster to the tray menu. */
export async function updateTrayAgentList(agents: AgentInfo[]): Promise<void> {
  const summarised = agents.map((a) => ({
    id: a.id,
    displayName: a.displayName,
    role: a.role,
    status: a.status,
  }));
  await safeInvoke('update_tray_agent_list', { agents: summarised });
}

/**
 * Subscribe the connection store to the tray; called once at boot.
 * Idempotent — second call replaces the prior subscription.
 */
let unsubConnection: (() => void) | null = null;
export function wireConnectionToTray(): void {
  if (!isTauri()) return;
  unsubConnection?.();
  // Push initial state.
  const s = useConnectionStore.getState();
  void updateTrayConnectionState(deriveTrayState(s.ws, s.api, isMockMode()));
  unsubConnection = useConnectionStore.subscribe((state, prev) => {
    if (state.ws !== prev.ws || state.api !== prev.api) {
      void updateTrayConnectionState(deriveTrayState(state.ws, state.api, isMockMode()));
    }
  });
}

/**
 * Wire the agent roster into the tray. Subscribes to the live
 * agentRegistry; the registry itself owns the WS bridge + 30s
 * backstop poll. Tray menu re-syncs every time the roster changes.
 */
let unsubAgents: (() => void) | null = null;
export function wireAgentRosterToTray(): void {
  if (!isTauri()) return;
  unsubAgents?.();
  unsubAgents = subscribeAgents((agents) => {
    void updateTrayAgentList(agents);
  });
}

/** Test hook. */
export function __resetTrayBridge(): void {
  unsubConnection?.();
  unsubConnection = null;
  unsubAgents?.();
  unsubAgents = null;
}
